SELECT [Sales Line].[Document Type], Item.[Line Code] AS Linea, [Sales Line].No_ AS Articolo, [Sales Line].[Constant Variable Code] AS CodiceColore, [Variable Code].Description AS Colore, Item.[Trademark Code] AS Marchio, [Sales Header].[Selling Season Code] AS Stagione, Sum(IIf([sales line.delete reason]='' Or IsNull([sales line.delete reason])=True,Val([no_ of pairs]),0)) AS PaiaConfermateREAL, Item.Description AS Descrizione, Item.[Description 2] AS Descrizione2, Item.[Product Family] AS FamigliaProdotto, Item.[Product Sex] AS GenereProdotto, Item.[Collection Code] AS [Collection Code], Item.[Vendor No_], Vendor.Name AS VendorName, IIf([moltiplicatore]<>1,Round([PaiaconfermateREAL]*[MOLTIPLICATORE]/10,0)*10,[paiaconfermatereal]) AS PaiaConfermate, Vendor_1.No_ AS Manufacturer, Vendor_1.Name AS ManufacturerName
FROM (((([Sales Line] INNER JOIN Item ON [Sales Line].No_ = Item.No_) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code]) AND ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group])) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_
WHERE (((Item.[advertising material])=0))
GROUP BY [Sales Line].[Document Type], Item.[Line Code], [Sales Line].No_, [Sales Line].[Constant Variable Code], [Variable Code].Description, Item.[Trademark Code], [Sales Header].[Selling Season Code], Item.Description, Item.[Description 2], Item.[Product Family], Item.[Product Sex], Item.[Collection Code], Item.[Vendor No_], Vendor.Name, Vendor_1.No_, Vendor_1.Name
HAVING ((([Sales Line].[Document Type])=1) AND ((Item.[Trademark Code])=[Maschere]![principale]![filtroMarchio]) AND (([Sales Header].[Selling Season Code])=[Maschere]![principale]![filtroStagione]))
ORDER BY Sum(IIf([sales line.delete reason]='' Or IsNull([sales line.delete reason])=True,Val([no_ of pairs]),0)) DESC;

